using System.ComponentModel;
using System.Text.Json;
using Microsoft.Extensions.AI;

// ---------------------------------------------------------------------------
// Research Agent – a .NET 10 console app that uses an AI agent with
// web-search and note-taking tools to research a topic and summarise findings.
// ---------------------------------------------------------------------------

// --- Configuration --------------------------------------------------------
var modelName = Environment.GetEnvironmentVariable("OPENAI_MODEL") ?? "gpt-4o-mini";
var apiKey    = Environment.GetEnvironmentVariable("OPENAI_API_KEY");
var baseUrl   = Environment.GetEnvironmentVariable("OPENAI_BASE_URL");

if (string.IsNullOrWhiteSpace(apiKey))
{
    Console.Error.WriteLine("Set the OPENAI_API_KEY environment variable.");
    return 1;
}

// --- Build the IChatClient pipeline with automatic function invocation -----
OpenAI.OpenAIClientOptions? clientOptions = null;
if (!string.IsNullOrWhiteSpace(baseUrl))
{
    clientOptions = new OpenAI.OpenAIClientOptions { Endpoint = new Uri(baseUrl) };
}

var openAIClient = new OpenAI.OpenAIClient(new System.ClientModel.ApiKeyCredential(apiKey), clientOptions);

IChatClient client = openAIClient
    .GetChatClient(modelName)
    .AsIChatClient()
    .AsBuilder()
    .UseFunctionInvocation()
    .Build();

// --- Tools ----------------------------------------------------------------
var notebook = new Notebook();

var tools = new AITool[]
{
    AIFunctionFactory.Create(WebSearchTool.SearchWeb),
    AIFunctionFactory.Create(notebook.AddNote),
    AIFunctionFactory.Create(notebook.GetNotes),
};

// --- Conversation setup ---------------------------------------------------
var topic = args.Length > 0
    ? string.Join(' ', args)
    : PromptForTopic();

Console.WriteLine($"\n🔍 Researching: {topic}\n");

var messages = new List<ChatMessage>
{
    new(ChatRole.System, """
        You are a research agent. Your goal is to thoroughly research the topic
        the user provides by following these steps:

        1. Use the SearchWeb tool multiple times with varied queries to gather
           information from different angles.
        2. Use the AddNote tool to record each important finding as you go.
        3. After you have gathered enough information (at least 3-5 searches),
           use GetNotes to review everything you have collected.
        4. Finally, provide a well-structured summary of your research to the
           user, citing the sources you found.

        Be thorough but concise. Focus on factual, up-to-date information.
        """),
    new(ChatRole.User, $"Please research the following topic: {topic}"),
};

var options = new ChatOptions
{
    Tools = [.. tools],
    ToolMode = ChatToolMode.Auto,
};

// --- Run the agent loop ---------------------------------------------------
Console.ForegroundColor = ConsoleColor.DarkGray;

await foreach (var update in client.GetStreamingResponseAsync(messages, options))
{
    if (update.Role == ChatRole.Assistant && update.Text is { Length: > 0 } text)
    {
        Console.ResetColor();
        Console.Write(text);
    }
}

Console.ResetColor();
Console.WriteLine("\n");
return 0;

// --- Helper ---------------------------------------------------------------
static string PromptForTopic()
{
    Console.Write("Enter a research topic: ");
    var topic = Console.ReadLine()?.Trim();
    if (string.IsNullOrWhiteSpace(topic))
    {
        Console.Error.WriteLine("No topic provided.");
        Environment.Exit(1);
    }
    return topic;
}

// ==========================================================================
// Tools
// ==========================================================================

/// <summary>Simulated web search tool that returns plausible search results.</summary>
static class WebSearchTool
{
    private static readonly HttpClient Http = new();

    [Description("Search the web for information on a query. Returns a list of result snippets with titles and URLs.")]
    public static async Task<string> SearchWeb(
        [Description("The search query string")] string query)
    {
        Console.ForegroundColor = ConsoleColor.Cyan;
        Console.WriteLine($"  🌐 Searching: \"{query}\"");
        Console.ResetColor();

        try
        {
            // Use DuckDuckGo Instant Answer API (free, no key required)
            var encoded = Uri.EscapeDataString(query);
            var url = $"https://api.duckduckgo.com/?q={encoded}&format=json&no_html=1&skip_disambig=1";
            var json = await Http.GetStringAsync(url);
            using var doc = JsonDocument.Parse(json);
            var root = doc.RootElement;

            var results = new List<string>();

            // Abstract (main answer)
            var abstractText = root.GetProperty("Abstract").GetString();
            var abstractUrl  = root.GetProperty("AbstractURL").GetString();
            var abstractSrc  = root.GetProperty("AbstractSource").GetString();
            if (!string.IsNullOrWhiteSpace(abstractText))
            {
                results.Add($"[{abstractSrc}] {abstractText}\n  URL: {abstractUrl}");
            }

            // Related topics
            if (root.TryGetProperty("RelatedTopics", out var topics))
            {
                foreach (var topic in topics.EnumerateArray().Take(5))
                {
                    var text = topic.TryGetProperty("Text", out var t) ? t.GetString() : null;
                    var link = topic.TryGetProperty("FirstURL", out var u) ? u.GetString() : null;
                    if (!string.IsNullOrWhiteSpace(text))
                        results.Add($"• {text}\n  URL: {link}");
                }
            }

            if (results.Count == 0)
                return $"No results found for \"{query}\". Try a different search query.";

            return string.Join("\n\n", results);
        }
        catch (Exception ex)
        {
            return $"Search failed ({ex.Message}). Try a different query.";
        }
    }
}

/// <summary>Simple notebook for the agent to record and review findings.</summary>
class Notebook
{
    private readonly List<string> _notes = [];

    [Description("Save a research note. Use this to record important findings as you research.")]
    public string AddNote(
        [Description("The note content to save")] string note)
    {
        _notes.Add(note);
        Console.ForegroundColor = ConsoleColor.Yellow;
        Console.WriteLine($"  📝 Note #{_notes.Count} saved");
        Console.ResetColor();
        return $"Note #{_notes.Count} saved successfully.";
    }

    [Description("Retrieve all saved research notes to review before writing your summary.")]
    public string GetNotes()
    {
        if (_notes.Count == 0)
            return "No notes saved yet.";

        Console.ForegroundColor = ConsoleColor.Green;
        Console.WriteLine($"  📋 Reviewing {_notes.Count} note(s)");
        Console.ResetColor();

        return string.Join("\n\n", _notes.Select((n, i) => $"--- Note #{i + 1} ---\n{n}"));
    }
}

