+/// <summary>Simulated web search tool that returns plausible search results.</summary>
+static class WebSearchTool
+{
+    private static readonly HttpClient Http = new();
+
+    [Description("Search the web for information on a query. Returns a list of result snippets with titles and URLs.")]
+    public static async Task<string> SearchWeb(
+        [Description("The search query string")] string query)
+    {
+        Console.ForegroundColor = ConsoleColor.Cyan;
+        Console.WriteLine($"  🌐 Searching: \"{query}\"");
+        Console.ResetColor();
+
+        try
+        {
+            // Use DuckDuckGo Instant Answer API (free, no key required)
+            var encoded = Uri.EscapeDataString(query);
+            var url = $"https://api.duckduckgo.com/?q={encoded}&format=json&no_html=1&skip_disambig=1";
+            var json = await Http.GetStringAsync(url);
+            using var doc = JsonDocument.Parse(json);
+            var root = doc.RootElement;
+
+            var results = new List<string>();
+
+            // Abstract (main answer)
+            var abstractText = root.GetProperty("Abstract").GetString();
+            var abstractUrl  = root.GetProperty("AbstractURL").GetString();
+            var abstractSrc  = root.GetProperty("AbstractSource").GetString();
+            if (!string.IsNullOrWhiteSpace(abstractText))
+            {
+                results.Add($"[{abstractSrc}] {abstractText}\n  URL: {abstractUrl}");
+            }
+
+            // Related topics
+            if (root.TryGetProperty("RelatedTopics", out var topics))
+            {
+                foreach (var topic in topics.EnumerateArray().Take(5))
+                {
+                    var text = topic.TryGetProperty("Text", out var t) ? t.GetString() : null;
+                    var link = topic.TryGetProperty("FirstURL", out var u) ? u.GetString() : null;
+                    if (!string.IsNullOrWhiteSpace(text))
+                        results.Add($"• {text}\n  URL: {link}");
+                }
+            }
+
+            if (results.Count == 0)
+                return $"No results found for \"{query}\". Try a different search query.";
+
+            return string.Join("\n\n", results);
+        }
+        catch (Exception ex)
+        {
+            return $"Search failed ({ex.Message}). Try a different query.";
+        }
+    }
+}
